#include<bits/stdc++.h>
using namespace std;
class FHQ_Treap
{
    private:
    struct node
    {
        long long l,r;
        long long val,key;
        long long siz;
    }t[100010];
    long long root,tot,siz;
    public:
    long long newnode(long long v)
    {
        t[++tot].val=v;
        t[tot].key=rand();
        t[tot].siz=1;
        return tot;
    }
    void pushup(long long x)
    {
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
    }
    void split(long long p,long long v,long long &x,long long &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        if(t[p].val<=v)
        {
            x=p;
            split(t[x].r,v,t[x].r,y);
        }
        else
        {
            y=p;
            split(t[y].l,v,x,t[y].l);
        }
        pushup(p);
    }
    long long merge(long long x,long long y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        if(t[x].key<t[y].key)
        {
            t[x].r=merge(t[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            t[y].l=merge(x,t[y].l);
            pushup(y);
            return y;
        }
    }
    void insert(long long v)
    {
        siz++;
        long long x,y,z;
        split(root,v,x,y);
        z=newnode(v);
        root=merge(merge(x,z),y);
    }
    void del(long long v)
    {
        siz--;
        long long x,y,z;
        split(root,v,x,z);
        split(x,v-1,x,y);
        y=merge(t[y].l,t[y].r);
        root=merge(merge(x,y),z);
    }
    long long getrnk(long long v)
    {
        long long x,y;
        split(root,v-1,x,y);
        long long ans=t[x].siz+1;
        root=merge(x,y);
        return ans;
    }
    private:
    long long getkth(long long p,long long v)
    {
        if(v<=t[t[p].l].siz)
        {
            return getkth(t[p].l,v);
        }
        if(v==t[t[p].l].siz+1)
        {
            return p;
        }
        return getkth(t[p].r,v-t[t[p].l].siz-1);
    }
    public:
    long long getkth(long long v)
    {
        return t[getkth(root,v)].val;
    }
    long long getpre(long long v)
    {
        long long x,y;
        split(root,v-1,x,y);
        long long p=getkth(x,t[x].siz);
        long long ans=t[p].val;
        root=merge(x,y);
        return ans;
    }
    long long getnxt(long long v)
    {
        long long x,y;
        split(root,v,x,y);
        long long p=getkth(y,1);
        long long ans=t[p].val;
        root=merge(x,y);
        return ans;
    }
    long long size()
    {
        return t[root].siz;
    }
    long long getmin()
    {
        return getkth(1);
    }
    long long getmax()
    {
        return getkth(size());
    }
    bool empty()
    {
        return size()==0;
    }
}t;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    stack<int> s;
    t.insert(0);
    t.insert(n+1);
    for(int i=1;i<=m;i++)
    {
        char op;
        cin>>op;
        int x;
        if(op!='R')
        {
            scanf("%d",&x);
        }
        if(op=='D')
        {
            t.insert(x);
            s.push(x);
        }
        else if(op=='R')
        {
            t.del(s.top());
            s.pop();
        }
        else
        {
            if(t.getpre(t.getnxt(x))==x)
            {
                printf("0\n");
                continue;
            }
            int pre=t.getpre(x),nxt=t.getnxt(x);
            printf("%d\n",nxt-pre-1);
        }
    }
    return 0;
}
